# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import json
import time
import hashlib
import secrets
from datetime import datetime, timedelta
from typing import Optional, Dict, Any

from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(32)

# Initialize Web3
w3 = Web3()

# In-memory stores (use Redis/DB in production)
nonce_store: Dict[str, Dict[str, Any]] = {}  # address -> {nonce, expires_at}
session_store: Dict[str, Dict[str, Any]] = {}  # session_token -> {address, expires_at}
user_store: Dict[str, Dict[str, Any]] = {}  # address -> user profile


NONCE_EXPIRY_SECONDS = 300  # 5 minutes
SESSION_EXPIRY_SECONDS = 3600  # 1 hour


def cleanup_expired_nonces():
    """Remove expired nonces from store."""
    now = time.time()
    expired = [addr for addr, data in nonce_store.items() if data['expires_at'] < now]
    for addr in expired:
        del nonce_store[addr]


def cleanup_expired_sessions():
    """Remove expired sessions from store."""
    now = time.time()
    expired = [token for token, data in session_store.items() if data['expires_at'] < now]
    for token in expired:
        del session_store[token]


def generate_nonce() -> str:
    """Generate a cryptographically secure random nonce."""
    return secrets.token_hex(16)


def generate_session_token() -> str:
    """Generate a secure session token."""
    return secrets.token_hex(32)


def create_sign_message(address: str, nonce: str) -> str:
    """Create the message that the user needs to sign."""
    return (
        f"Welcome to Web3 Auth!\n\n"
        f"Please sign this message to authenticate.\n\n"
        f"Wallet: {address}\n"
        f"Nonce: {nonce}\n"
        f"Timestamp: {datetime.utcnow().isoformat()}"
    )


def verify_ethereum_signature(message: str, signature: str, expected_address: str) -> bool:
    """
    Verify an Ethereum signature and check if the recovered address matches.
    
    Args:
        message: The original message that was signed
        signature: The hex signature string
        expected_address: The Ethereum address we expect to have signed
        
    Returns:
        True if signature is valid and matches the expected address
    """
    try:
        # Encode the message as per EIP-191
        message_encoded = encode_defunct(text=message)
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(
            message_encoded,
            signature=signature
        )
        
        # Compare addresses (case-insensitive)
        return recovered_address.lower() == expected_address.lower()
    except Exception as e:
        app.logger.error(f"Signature verification failed: {e}")
        return False


def is_valid_ethereum_address(address: str) -> bool:
    """Check if a string is a valid Ethereum address."""
    try:
        return Web3.is_address(address)
    except Exception:
        return False


def require_auth(f):
    """Decorator to require authentication for routes."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        
        if not auth_header.startswith('Bearer '):
            return jsonify({
                'success': False,
                'error': 'Missing or invalid Authorization header'
            }), 401
        
        token = auth_header[7:]  # Strip 'Bearer '
        
        cleanup_expired_sessions()
        
        session = session_store.get(token)
        if not session:
            return jsonify({
                'success': False,
                'error': 'Invalid or expired session token'
            }), 401
        
        if session['expires_at'] < time.time():
            del session_store[token]
            return jsonify({
                'success': False,
                'error': 'Session expired'
            }), 401
        
        # Attach user address to request context
        request.user_address = session['address']
        request.session_token = token
        
        return f(*args, **kwargs)
    
    return decorated


@app.route('/auth/nonce', methods=['POST'])
def get_nonce():
    """
    Step 1: Request a nonce for a given Ethereum address.
    The client sends their address and receives a nonce to sign.
    """
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({
            'success': False,
            'error': 'Ethereum address is required'
        }), 400
    
    address = data['address']
    
    if not is_valid_ethereum_address(address):
        return jsonify({
            'success': False,
            'error': 'Invalid Ethereum address'
        }), 400
    
    # Normalize address to checksum format
    address = Web3.to_checksum_address(address)
    
    cleanup_expired_nonces()
    
    # Generate and store nonce
    nonce = generate_nonce()
    message = create_sign_message(address, nonce)
    
    nonce_store[address.lower()] = {
        'nonce': nonce,
        'message': message,
        'expires_at': time.time() + NONCE_EXPIRY_SECONDS
    }
    
    return jsonify({
        'success': True,
        'data': {
            'address': address,
            'nonce': nonce,
            'message': message,
            'expires_in': NONCE_EXPIRY_SECONDS
        }
    }), 200


@app.route('/auth/verify', methods=['POST'])
def verify_signature():
    """
    Step 2: Verify the signed message and authenticate the user.
    The client sends the signed message and receives a session token.
    """
    data = request.get_json()
    
    if not data:
        return jsonify({
            'success': False,
            'error': 'Request body is required'
        }), 400
    
    required_fields = ['address', 'signature']
    for field in required_fields:
        if field not in data:
            return jsonify({
                'success': False,
                'error': f'{field} is required'
            }), 400
    
    address = data['address']
    signature = data['signature']
    
    if not is_valid_ethereum_address(address):
        return jsonify({
            'success': False,
            'error': 'Invalid Ethereum address'
        }), 400
    
    address_lower = address.lower()
    
    # Check if nonce exists and is not expired
    cleanup_expired_nonces()
    
    nonce_data = nonce_store.get(address_lower)
    if not nonce_data:
        return jsonify({
            'success': False,
            'error': 'No pending authentication request. Please request a nonce first.'
        }), 400
    
    if nonce_data['expires_at'] < time.time():
        del nonce_store[address_lower]
        return jsonify({
            'success': False,
            'error': 'Nonce has expired. Please request a new one.'
        }), 400
    
    message = nonce_data['message']
    
    # Verify the signature
    is_valid = verify_ethereum_signature(message, signature, address)
    
    # Always consume the nonce (prevent replay attacks)
    del nonce_store[address_lower]
    
    if not is_valid:
        return jsonify({
            'success': False,
            'error': 'Invalid signature'
        }), 401
    
    # Authentication successful - create session
    session_token = generate_session_token()
    checksum_address = Web3.to_checksum_address(address)
    
    session_store[session_token] = {
        'address': checksum_address,
        'expires_at': time.time() + SESSION_EXPIRY_SECONDS,
        'created_at': time.time()
    }
    
    # Create or update user profile
    if address_lower not in user_store:
        user_store[address_lower] = {
            'address': checksum_address,
            'created_at': datetime.utcnow().isoformat(),
            'last_login': datetime.utcnow().isoformat(),
            'login_count': 1
        }
    else:
        user_store[address_lower]['last_login'] = datetime.utcnow().isoformat()
        user_store[address_lower]['login_count'] += 1
    
    return jsonify({
        'success': True,
        'data': {
            'address': checksum_address,
            'session_token': session_token,
            'expires_in': SESSION_EXPIRY_SECONDS,
            'user': user_store[address_lower]
        }
    }), 200


@app.route('/auth/me', methods=['GET'])
@require_auth
def get_current_user():
    """Get the currently authenticated user's profile."""
    address = request.user_address
    user = user_store.get(address.lower(), {})
    
    return jsonify({
        'success': True,
        'data': {
            'address': address,
            'user': user
        }
    }), 200


@app.route('/auth/logout', methods=['POST'])
@require_auth
def logout():
    """Invalidate the current session."""
    token = request.session_token
    
    if token in session_store:
        del session_store[token]
    
    return jsonify({
        'success': True,
        'message': 'Successfully logged out'
    }), 200


@app.route('/auth/refresh', methods=['POST'])
@require_auth
def refresh_session():
    """Refresh the current session token."""
    old_token = request.session_token
    address = request.user_address
    
    # Invalidate old session
    if old_token in session_store:
        del session_store[old_token]
    
    # Create new session
    new_token = generate_session_token()
    session_store[new_token] = {
        'address': address,
        'expires_at': time.time() + SESSION_EXPIRY_SECONDS,
        'created_at': time.time()
    }
    
    return jsonify({
        'success': True,
        'data': {
            'session_token': new_token,
            'expires_in': SESSION_EXPIRY_SECONDS
        }
    }), 200


@app.route('/auth/verify-token', methods=['POST'])
def verify_token():
    """Verify if a session token is still valid (for microservices)."""
    data = request.get_json()
    
    if not data or 'token' not in data:
        return jsonify({
            'success': False,
            'error': 'Token is required'
        }), 400
    
    token = data['token']
    session = session_store.get(token)
    
    if not session or session['expires_at'] < time.time():
        return jsonify({
            'success': False,
            'valid': False,
            'error': 'Invalid or expired token'
        }), 401
    
    return jsonify({
        'success': True,
        'valid': True,
        'data': {
            'address': session['address'],
            'expires_at': session['expires_at']
        }
    }), 200


