def demo_client_flow():
    """
    Demonstrates the complete authentication flow programmatically.
    This simulates what a frontend client would do.
    """
    from eth_account import Account
    
    print("=" * 60)
    print("Web3 Authentication Demo")
    print("=" * 60)
    
    # Generate a test account
    account = Account.create()
    print(f"\nTest wallet address: {account.address}")
    print(f"Test private key: {account.key.hex()}")
    
    with app.test_client() as client:
        # Step 1: Request nonce
        print("\n--- Step 1: Request Nonce ---")
        response = client.post('/auth/nonce', json={
            'address': account.address
        })
        nonce_response = response.get_json()
        print(f"Response: {json.dumps(nonce_response, indent=2)}")
        
        if not nonce_response['success']:
            print("Failed to get nonce!")
            return
        
        message = nonce_response['data']['message']
        print(f"\nMessage to sign:\n{message}")
        
        # Step 2: Sign the message (client-side)
        print("\n--- Step 2: Sign Message ---")
        message_encoded = encode_defunct(text=message)
        signed_message = w3.eth.account.sign_message(
            message_encoded,
            private_key=account.key
        )
        signature = signed_message.signature.hex()
        print(f"Signature: {signature[:40]}...")
        
        # Step 3: Verify signature and authenticate
        print("\n--- Step 3: Verify & Authenticate ---")
        response = client.post('/auth/verify', json={
            'address': account.address,
            'signature': signature
        })
        auth_response = response.get_json()
        print(f"Response: {json.dumps(auth_response, indent=2)}")
        
        if not auth_response['success']:
            print("Authentication failed!")
            return
        
        session_token = auth_response['data']['session_token']
        
        # Step 4: Access protected resource
        print("\n--- Step 4: Access Protected Resource ---")
        response = client.get('/protected/resource', headers={
            'Authorization': f'Bearer {session_token}'
        })
        protected_response = response.get_json()
        print(f"Response: {json.dumps(protected_response, indent=2)}")
        
        # Step 5: Get user profile
        print("\n--- Step 5: Get User Profile ---")
        response = client.get('/auth/me', headers={
            'Authorization': f'Bearer {session_token}'
        })
        profile_response = response.get_json()
        print(f"Response: {json.dumps(profile_response, indent=2)}")
        
        # Step 6: Refresh token
        print("\n--- Step 6: Refresh Token ---")
        response = client.post('/auth/refresh', headers={
            'Authorization': f'Bearer {session_token}'
        })
        refresh_response = response.get_json()
        print(f"Response: {json.dumps(refresh_response, indent=2)}")
        
        new_token = refresh_response['data']['session_token']
        
        # Step 7: Verify old token is invalid
        print("\n--- Step 7: Verify Old Token Invalid ---")
        response = client.get('/auth/me', headers={
            'Authorization': f'Bearer {session_token}'
        })
        old_token_response = response.get_json()
        print(f"Old token response: {json.dumps(old_token_response, indent=2)}")
        
        # Step 8: Logout
        print("\n--- Step 8: Logout ---")
        response = client.post('/auth/logout', headers={
            'Authorization': f'Bearer {new_token}'
        })
        logout_response = response.get_json()
        print(f"Response: {json.dumps(logout_response, indent=2)}")
        
        # Step 9: Verify session is invalidated
        print("\n--- Step 9: Verify Session Invalidated ---")
        response = client.get('/protected/resource', headers={
            'Authorization': f'Bearer {new_token}'
        })
        invalid_response = response.get_json()
        print(f"Response: {json.dumps(invalid_response, indent=2)}")
        
        # Health check
        print("\n--- Health Check ---")
        response = client.get('/health')
        health_response = response.get_json()
        print(f"Response: {json.dumps(health_response, indent=2)}")
    
    print("\n" + "=" * 60)
    print("Demo complete!")
    print("=" * 60)


